section.code:
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/semantic-tokens-and-modes.json",
  "type": "object",
  "required": ["__faion_header__", "format", "layers", "modes", "tokens", "pipeline"],
  "properties": {
    "__faion_header__": {
      "type": "object",
      "required": ["methodology", "version", "produces"],
      "properties": {
        "methodology": {"const": "semantic-tokens-and-modes"},
        "version": {"type": "string", "pattern": "^\\d+\\.\\d+\\.\\d+$"},
        "produces": {"const": "config"}
      }
    },
    "format": {"const": "dtcg"},
    "layers": {
      "type": "object",
      "required": ["reference", "system", "component"],
      "properties": {
        "reference": {"type": "boolean", "const": true},
        "system":    {"type": "boolean", "const": true},
        "component": {"type": "boolean", "const": true}
      }
    },
    "modes": {
      "type": "array",
      "items": {"enum": ["light", "dark", "high-contrast", "compact", "comfortable", "brand-a", "brand-b", "white-label"]},
      "minItems": 1
    },
    "tokens": {
      "type": "object",
      "required": ["system"],
      "properties": {
        "system": {
          "type": "object",
          "additionalProperties": {
            "type": "object",
            "required": ["$type", "values_by_mode"],
            "properties": {
              "$type": {"enum": ["color", "dimension", "fontFamily", "fontWeight", "duration", "cubicBezier", "shadow"]},
              "intent": {"type": "string"},
              "values_by_mode": {"type": "object", "additionalProperties": {"type": "string"}}
            }
          }
        }
      }
    },
    "pipeline": {
      "type": "object",
      "required": ["builder", "platforms"],
      "properties": {
        "builder": {"enum": ["style-dictionary", "tokens-studio", "specify"]},
        "platforms": {"type": "array", "items": {"enum": ["css", "swift", "compose", "android-xml"]}, "minItems": 1}
      }
    },
    "lint": {
      "type": "object",
      "properties": {
        "reject_raw_hex_in_components": {"type": "boolean", "const": true},
        "reject_direct_reference_in_components": {"type": "boolean", "const": true}
      }
    },
    "visual_regression": {
      "type": "object",
      "required": ["tool", "snapshot_every_mode"],
      "properties": {
        "tool": {"enum": ["chromatic", "percy", "loki"]},
        "snapshot_every_mode": {"type": "boolean", "const": true}
      }
    }
  }
}

example.code:
{
  "__faion_header__": {"methodology": "semantic-tokens-and-modes", "version": "1.1.0", "produces": "config"},
  "format": "dtcg",
  "layers": {"reference": true, "system": true, "component": true},
  "modes": ["light", "dark", "high-contrast"],
  "tokens": {
    "system": {
      "color.action.primary": {
        "$type": "color",
        "intent": "primary interactive surface",
        "values_by_mode": {"light": "{color.blue.600}", "dark": "{color.blue.400}", "high-contrast": "{color.blue.900}"}
      }
    }
  },
  "pipeline": {"builder": "style-dictionary", "platforms": ["css", "swift", "compose"]},
  "lint": {"reject_raw_hex_in_components": true, "reject_direct_reference_in_components": true},
  "visual_regression": {"tool": "chromatic", "snapshot_every_mode": true}
}
